scene.add(new THREE.AmbientLight(0x35596a,0.9));
const sun=new THREE.DirectionalLight(0xfff0dd,1.15); sun.position.set(-3,2,2.5); scene.add(sun);
const stG=new THREE.BufferGeometry(),sp=[]; for(let i=0;i<700;i++){const r=18+Math.random()*22,th=Math.random()*6.283,ph=Math.acos(2*Math.random()-1);sp.push(r*Math.sin(ph)*Math.cos(th),r*Math.cos(ph),r*Math.sin(ph)*Math.sin(th));}
stG.setAttribute('position',new THREE.Float32BufferAttribute(sp,3));
scene.add(new THREE.Points(stG,new THREE.PointsMaterial({color:0x9fc6cf,size:0.06,transparent:true,opacity:0.5})));

function glowTex(){const c=document.createElement('canvas');c.width=c.height=128;const g=c.getContext('2d');
  const gr=g.createRadialGradient(64,64,0,64,64,64);
  gr.addColorStop(0,'rgba(255,255,255,1)');gr.addColorStop(.18,'rgba(255,255,255,.9)');
  gr.addColorStop(.45,'rgba(255,255,255,.4)');gr.addColorStop(1,'rgba(255,255,255,0)');
  g.fillStyle=gr;g.fillRect(0,0,128,128);return new THREE.CanvasTexture(c);}
const GTEX=glowTex();
function llv(lat,lon,r){const phi=(90-lat)*Math.PI/180,th=lon*Math.PI/180;
  return new THREE.Vector3(r*Math.sin(phi)*Math.cos(th),r*Math.cos(phi),r*Math.sin(phi)*Math.sin(th));}

const nodes=ISLANDS.map(([key,label,lat,lon])=>{
  const base=llv(lat,lon,1.012);
  const mat=new THREE.SpriteMaterial({map:GTEX,transparent:true,blending:THREE.AdditiveBlending,depthTest:true,depthWrite:false,opacity:0});
  const spr=new THREE.Sprite(mat); spr.position.copy(base); globe.add(spr);
  const el=document.createElement('div'); el.className='lbl'; el.textContent=label; document.getElementById('labels').appendChild(el);
  return {key,label,base,spr,mat,el,cur:{size:0.05,opacity:0,color:new THREE.Color(0.2,0.3,0.35)}};
});
globe.rotation.y=THREE.MathUtils.degToRad(90-188); globe.rotation.x=THREE.MathUtils.degToRad(8);

// ── responsibility flow-lines (Act III: "least cause, greatest cost") ──
// Placeholder emitter coordinates — swap for precise capitals/centroids once real per-country
// emissions figures are wired in.
const EMITTERS=[["USA",39.8,-98.6],["China",35.0,105.0],["EU",50.0,10.0],["Australia",-25.0,133.0]];
const RESPONSIBILITY_TARGETS=["Tuvalu","Kiribati","Marshall Islands","Fiji","Vanuatu","Solomon Islands","Tonga"];
let flowEnabled=false;
const FLOWLINES=[];
function addFlowLine(fromLatLng,toLatLng,options={}){
  const opts=Object.assign({color:0xffb46a,opacity:0.26,particleCount:2,speed:0.12,arcHeight:0.3},options);
  const from=llv(fromLatLng[0],fromLatLng[1],1.001);
  const to=llv(toLatLng[0],toLatLng[1],1.001);
  const control=new THREE.Vector3().addVectors(from,to).multiplyScalar(0.5);
  const chordFrac=clamp(from.distanceTo(to)/2,0,1);
  control.normalize().multiplyScalar(1+opts.arcHeight*(0.4+chordFrac));
  const curve=new THREE.QuadraticBezierCurve3(from,control,to);
  const geo=new THREE.BufferGeometry().setFromPoints(curve.getPoints(48));
  const mat=new THREE.LineBasicMaterial({color:opts.color,transparent:true,opacity:opts.opacity,blending:THREE.AdditiveBlending,depthWrite:false});
  const line=new THREE.Line(geo,mat); line.visible=false; globe.add(line);
  const particles=[];
  for(let i=0;i<opts.particleCount;i++){
    const pmat=new THREE.SpriteMaterial({map:GTEX,transparent:true,blending:THREE.AdditiveBlending,depthWrite:false,opacity:opts.opacity*1.8});
    const spr=new THREE.Sprite(pmat); spr.scale.set(0.055,0.055,1); spr.visible=false; globe.add(spr);
    particles.push({spr,t:i/opts.particleCount});
  }
  const fl={curve,line,particles,speed:opts.speed};
  FLOWLINES.push(fl); return fl;
}
RESPONSIBILITY_TARGETS.forEach(key=>{
  const isl=ISLANDS.find(i=>i[0]===key); if(!isl)return;
  EMITTERS.forEach(([,lat,lon])=>addFlowLine([lat,lon],[isl[2],isl[3]]));
});
function setFlowLines(on){ flowEnabled=on; FLOWLINES.forEach(fl=>{ fl.line.visible=on; fl.particles.forEach(p=>p.spr.visible=on); }); }
function updateFlowLines(dt){ if(!flowEnabled)return;
  FLOWLINES.forEach(fl=>fl.particles.forEach(p=>{
    p.t+=dt*fl.speed; if(p.t>1)p.t-=1;
    p.spr.position.copy(fl.curve.getPointAt(clamp(p.t,0,0.999)));
  })); }

// ── state ──
let actIdx=0,t=0,playing=true,dragging=false,px=0,py=0,velY=0,autoSpin=true;
const dom=renderer.domElement;
function down(e){dragging=true;autoSpin=false;const p=e.touches?e.touches[0]:e;px=p.clientX;py=p.clientY;}
function moveE(e){const p=e.touches?e.touches[0]:e;const cx=p.clientX,cy=p.clientY;
  if(dragging){const dx=cx-px,dy=cy-py;globe.rotation.y+=dx*0.005;velY=dx*0.005;globe.rotation.x=clamp(globe.rotation.x+dy*0.005,-0.9,0.9);px=cx;py=cy;}
  ray(cx,cy);}
function up(){dragging=false;}
dom.addEventListener('mousedown',down);window.addEventListener('mousemove',moveE);window.addEventListener('mouseup',up);
dom.addEventListener('touchstart',down,{passive:true});window.addEventListener('touchmove',moveE,{passive:true});window.addEventListener('touchend',up);

const rc=new THREE.Raycaster(),m2=new THREE.Vector2(),tip=document.getElementById('tip');
let curYear=1995;
function ray(cx,cy){m2.x=(cx/innerWidth)*2-1;m2.y=-(cy/innerHeight)*2+1;rc.setFromCamera(m2,camera);
  const hit=rc.intersectObjects(nodes.map(n=>n.spr).filter(s=>s.material.opacity>0.05));
  if(hit.length){const n=nodes.find(o=>o.spr===hit[0].object);const A=ACTS[actIdx];const v=A.value(n.key,curYear);
    tip.innerHTML=`<b>${n.label}</b> &nbsp; <span>${A.tip(v)}</span>`;tip.style.left=cx+'px';tip.style.top=cy+'px';tip.style.opacity=1;}
  else tip.style.opacity=0;}

// dock
const playBtn=document.getElementById('play'),scrub=document.getElementById('scrub'),actsEl=document.getElementById('acts'),flowBtn=document.getElementById('flowToggle');
ACTS.forEach((a,i)=>{const d=document.createElement('div');d.className='act';d.textContent=a.num;d.onclick=()=>gotoAct(i);actsEl.appendChild(d);});
playBtn.onclick=()=>{playing=!playing;playBtn.textContent=playing?'❚❚':'►';};
scrub.oninput=()=>{playing=false;playBtn.textContent='►';t=scrub.value/1000;};
flowBtn.onclick=()=>{setFlowLines(!flowEnabled);flowBtn.classList.toggle('on',flowEnabled);};
function gotoAct(i){actIdx=i;t=0;playing=true;playBtn.textContent='❚❚';refreshActUI();}

const elNum=document.querySelector('#actband .num'),elTitle=document.querySelector('#actband h1'),
      elYear=document.querySelector('#year .big'),elYLab=document.querySelector('#year .lab'),
      elCap=document.getElementById('caption'),elLeg=document.getElementById('legend');
let lastChap=null;
function refreshActUI(){const A=ACTS[actIdx];
  elNum.textContent=A.num+" · "+A.id.toUpperCase();
  elTitle.innerHTML=A.title.map(p=>Array.isArray(p)?`<em>${p[0]}</em>`:p).join("");
  elYLab.textContent=A.yearLabel;
  const [c0,c1]=A.legend[1];
  elLeg.innerHTML=`<span class="sw" style="background:linear-gradient(90deg,rgb(${c0.join(',')}),rgb(${c1.join(',')}))"></span>${A.legend[0]}`;
  [...actsEl.children].forEach((d,i)=>d.classList.toggle('on',i===actIdx));
  lastChap=null;}
function setCap(ch){if(ch===lastChap)return;lastChap=ch;
  elCap.innerHTML=`<div class="k">${ch.k}</div><h2>${ch.t}</h2><p>${ch.b}</p>`;
  elCap.classList.remove('fade');void elCap.offsetWidth;elCap.classList.add('fade');}
function chapterFor(A,y){let c=A.chapters[0];for(const ch of A.chapters)if(y>=ch.y)c=ch;return c;}

const tmp=new THREE.Vector3();
function update(dt){
  const A=ACTS[actIdx]; const year=lerp(A.range[0],A.range[1],t); curYear=year;
  elYear.textContent=Math.round(year);
  setCap(chapterFor(A,Math.round(year)));
  document.getElementById('brand').style.opacity = (actIdx===0&&t<0.03)?0:.8;

  // ocean tint (warming act)
  let meanAnom=0,nA=0;
  nodes.forEach(n=>{
    let v=A.value(n.key,year);
    let size=A.size(v,n.key,year)||0;
    let opacity = (v==null||size<=0)?0 : 0.92;
    if(A.id==='shocks'&&(v==null||v<=0))opacity=0;
    let target=A.color(v,n.key);
    if(A.oceanTint&&v!=null){meanAnom+=v;nA++;}
    // pulse for shocks
    if(A.pulse&&size>0){size*=1+0.12*Math.sin(performance.now()*0.004+n.base.x*3);}
    // ease
    const e=clamp(dt*4,0,1);
    n.cur.size=lerp(n.cur.size,size,e);
    n.cur.opacity=lerp(n.cur.opacity,opacity,e);
    n.cur.color.lerp(target,e);
    n.spr.scale.set(Math.max(n.cur.size,0.001),Math.max(n.cur.size,0.001),1);
    n.mat.opacity=n.cur.opacity*(0.35+0.65*clamp(n.cur.size*2,0,1));
    n.mat.color.copy(n.cur.color);
    // label
    tmp.copy(n.base).applyMatrix4(globe.matrixWorld);
    const facing=tmp.z; const pr=tmp.clone().project(camera);
    const showLbl=(A.id==='arrivals'? (v!=null&&v>60000) : A.id==='shocks'? (v!=null&&v>50000) : n.cur.size>0.18) && facing>0.15 && pr.z<1;
    if(showLbl){n.el.style.display='block';n.el.style.left=((pr.x*.5+.5)*innerWidth)+'px';
      n.el.style.top=((-pr.y*.5+.5)*innerHeight-n.cur.size*70)+'px';n.el.style.opacity=clamp((facing-0.15)*3,0,1);}
    else n.el.style.display='none';
  });
  if(A.oceanTint&&nA){const tgt=A.oceanTint(meanAnom/nA);oceanMat.color.lerp(tgt,clamp(dt*2,0,1));}
  else oceanMat.color.lerp(new THREE.Color(0x0a2c37),clamp(dt*2,0,1));
}

let prev=performance.now();
function animate(){requestAnimationFrame(animate);
  const now=performance.now(),dt=Math.min((now-prev)/1000,0.05);prev=now;
  if(playing){t+=dt*0.045;if(t>=1){t=1;if(actIdx<ACTS.length-1){gotoAct(actIdx+1);}else{playing=false;playBtn.textContent='►';}}}
  scrub.value=t*1000;
  if(!dragging){if(autoSpin)globe.rotation.y+=0.0006;else{globe.rotation.y+=velY;velY*=0.94;if(Math.abs(velY)<0.0002)velY=0;}}
  globe.updateMatrixWorld(); update(dt); updateFlowLines(dt); renderer.render(scene,camera);}
function resize(){camera.aspect=innerWidth/innerHeight;camera.updateProjectionMatrix();renderer.setSize(innerWidth,innerHeight);}
window.addEventListener('resize',resize);resize();
refreshActUI();playBtn.textContent='❚❚';animate();
